import { UsersGridComponent } from "components/users/UsersGridComponent.js";
import { Router } from "../../@still/routing/router.js";

export class HomeComponent extends ViewComponent {

    isPublic = true;
    template = `
        &lt;h1&gt;
            Welcome to the main page
        &lt;/h1&gt;
        &lt;a (click)="gotoUsersGrid()"&gt;List Users&lt;/a&gt;
    `;

    constructor() {
        super();
    }

    gotoUsersGrid(){
        Router.goto(UsersGridComponent);
    }

}
</code></pre> HomeComponent.js<pre><code>import { ViewComponent } from "../../@still/component/super/ViewComponent.js";

export class UsersGridComponent extends ViewComponent {

    isPublic = true;
    template = `
        &lt;h2&gt;Users Data&lt;/h2&gt;

        &lt;table&gt;
            &lt;tr&gt;
                &lt;th&gt;ID&lt;/th&gt;
                &lt;th&gt;Name&lt;/th&gt;
                &lt;th&gt;Email&lt;/th&gt;
                &lt;th&gt;Role&lt;/th&gt;
            &lt;/tr&gt;
            &lt;tr&gt;
                &lt;td&gt;1&lt;/td&gt;
                &lt;td&gt;Alice Johnson&lt;/td&gt;
                &lt;td&gt;alice@example.com&lt;/td&gt;
                &lt;td&gt;Admin&lt;/td&gt;
            &lt;/tr&gt;
            &lt;tr&gt;
                &lt;td&gt;2&lt;/td&gt;
                &lt;td&gt;Bob Smith&lt;/td&gt;
                &lt;td&gt;bob@example.com&lt;/td&gt;
                &lt;td&gt;Editor&lt;/td&gt;
            &lt;/tr&gt;
        &lt;/table&gt;
    `;

    constructor() {
        super();
    }

}
</code></pre> Routing considerations <p>For this example routing is implemented inside another method which then We're passing the component we want to navigate/go to, follow such component.</p> <p>Important consideration</p> <p>In the above code, on the HomeComponent we have the Route.goto() (line 20) being called inside the component method gotoUsersGrid(), as this method could be named anything (following  JS naming convention), nevertheless, this is then called on the template  tag (line 12), as this is the practice in StillJS.</p>
